import{_ as a,c as t,o as s,a1 as n}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"自動コンテキスト注入の仕組み | opencode-supermemory","description":"コンテキスト注入の仕組みを学びます。セッション開始時にプロファイルと知識を自動取得し、キーワードトリガーで記憶を保存する方法を解説します。","frontmatter":{"title":"自動コンテキスト注入の仕組み | opencode-supermemory","sidebarTitle":"コンテキスト注入","subtitle":"自動コンテキスト注入メカニズム：Agent に\\"予知能力\\"を","description":"コンテキスト注入の仕組みを学びます。セッション開始時にプロファイルと知識を自動取得し、キーワードトリガーで記憶を保存する方法を解説します。","tags":["context","injection","prompt","memory"],"prerequisite":["start-getting-started"],"order":1},"headers":[],"relativePath":"ja/supermemoryai/opencode-supermemory/core/context-injection/index.md","filePath":"ja/supermemoryai/opencode-supermemory/core/context-injection/index.md"}'),o={name:"ja/supermemoryai/opencode-supermemory/core/context-injection/index.md"};function i(r,e,l,p,d,c){return s(),t("div",null,[...e[0]||(e[0]=[n(`<h1 id="自動コンテキスト注入メカニズム-agent-に-予知能力-を" tabindex="-1">自動コンテキスト注入メカニズム：Agent に&quot;予知能力&quot;を <a class="header-anchor" href="#自動コンテキスト注入メカニズム-agent-に-予知能力-を" aria-label="Permalink to &quot;自動コンテキスト注入メカニズム：Agent に&quot;予知能力&quot;を&quot;">​</a></h1><h2 id="この章で学べること" tabindex="-1">この章で学べること <a class="header-anchor" href="#この章で学べること" aria-label="Permalink to &quot;この章で学べること&quot;">​</a></h2><p>この章では、以下のことができるようになります：</p><ol><li><strong>理解</strong>：なぜ Agent は最初からあなたのコーディング習慣とプロジェクトのアーキテクチャを知っているのか。</li><li><strong>習得</strong>：コンテキスト注入の「三次元モデル」（ユーザープロファイル、プロジェクト知識、関連記憶）。</li><li><strong>習得</strong>：キーワード（&quot;Remember this&quot; など）を使用して、Agent の記憶動作を能動的に制御する方法。</li><li><strong>設定</strong>：注入する項目数を調整し、コンテキストの長さと情報の豊富さのバランスを取る方法。</li></ol><hr><h2 id="基本的な考え方" tabindex="-1">基本的な考え方 <a class="header-anchor" href="#基本的な考え方" aria-label="Permalink to &quot;基本的な考え方&quot;">​</a></h2><p>記憶プラグインが存在する前は、新しいセッションを開始するたびに Agent は白紙の状態でした。毎回繰り返し「TypeScript を使用しています」「このプロジェクトは Next.js を使用しています」と伝える必要がありました。</p><p><strong>コンテキスト注入（Context Injection）</strong> はこの問題を解決します。これは Agent が起動した瞬間に、その脳に「任務概要」を押し込むようなものです。</p><h3 id="トリガーのタイミング" tabindex="-1">トリガーのタイミング <a class="header-anchor" href="#トリガーのタイミング" aria-label="Permalink to &quot;トリガーのタイミング&quot;">​</a></h3><p>opencode-supermemory は非常に控えめで、<strong>セッションの最初のメッセージ</strong>のみで自動注入をトリガーします。</p><ul><li><strong>なぜ最初なのか？</strong>：これはセッションの基調を決定する重要な瞬間だからです。</li><li><strong>その後のメッセージは？</strong>：会話の流れを妨げないために、その後のメッセージでは自動注入は行われません（以下の「キーワードトリガー」を参照）。</li></ul><h3 id="三次元注入モデル" tabindex="-1">三次元注入モデル <a class="header-anchor" href="#三次元注入モデル" aria-label="Permalink to &quot;三次元注入モデル&quot;">​</a></h3><p>プラグインは 3 種類のデータを並行して取得し、<code>[SUPERMEMORY]</code> プロンプトブロックに組み合わせます：</p><table tabindex="0"><thead><tr><th>データ次元</th><th>ソース</th><th>役割</th><th>例</th></tr></thead><tbody><tr><td><strong>1. ユーザープロファイル</strong> (Profile)</td><td><code>getProfile</code></td><td>あなたの長期の好み</td><td>&quot;ユーザーは簡潔な返信を好む&quot;、&quot;矢印関数を好む&quot;</td></tr><tr><td><strong>2. プロジェクト知識</strong> (Project)</td><td><code>listMemories</code></td><td>現在のプロジェクトのグローバル知識</td><td>&quot;このプロジェクトは Clean Architecture を採用&quot;、&quot;API は src/api に配置&quot;</td></tr><tr><td><strong>3. 関連記憶</strong> (Relevant)</td><td><code>searchMemories</code></td><td>あなたの最初のメッセージに関連する過去の経験</td><td>&quot;この Bug をどう直すか&quot;と尋ねると、以前の同様の修正記録が検索される</td></tr></tbody></table><hr><h2 id="何が注入されるのか" tabindex="-1">何が注入されるのか？ <a class="header-anchor" href="#何が注入されるのか" aria-label="Permalink to &quot;何が注入されるのか？&quot;">​</a></h2><p>OpenCode で最初のメッセージを送信すると、プラグインはバックグラウンドで次の内容を System Prompt に挿入します。</p><details class="details custom-block"><summary>注入内容の実際の構造を表示するにはクリック</summary><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[SUPERMEMORY]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>User Profile:</span></span>
<span class="line"><span>- User prefers concise responses</span></span>
<span class="line"><span>- User uses Zod for all validations</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Recent Context:</span></span>
<span class="line"><span>- Working on auth module refactoring</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Project Knowledge:</span></span>
<span class="line"><span>- [100%] Architecture follows MVC pattern</span></span>
<span class="line"><span>- [100%] Use &#39;npm run test&#39; for testing</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Relevant Memories:</span></span>
<span class="line"><span>- [85%] Previous fix for hydration error: use useEffect</span></span></code></pre></div></details><p>Agent はこの情報を見ると、このプロジェクトで長く働いているベテラン従業員のように振る舞い、新入りの実習生のようにはなりません。</p><hr><h2 id="キーワードトリガーメカニズム-nudge" tabindex="-1">キーワードトリガーメカニズム (Nudge) <a class="header-anchor" href="#キーワードトリガーメカニズム-nudge" aria-label="Permalink to &quot;キーワードトリガーメカニズム (Nudge)&quot;">​</a></h2><p>冒頭の自動注入に加えて、会話中にいつでも記憶機能を「覚醒」させることができます。</p><p>プラグインには <strong>キーワード検出器</strong> が組み込まれています。メッセージに特定のトリガーワードが含まれていると、プラグインは Agent に「見えないヒント（Nudge）」を送信し、保存ツールを呼び出すことを強制します。</p><h3 id="デフォルトのトリガーワード" tabindex="-1">デフォルトのトリガーワード <a class="header-anchor" href="#デフォルトのトリガーワード" aria-label="Permalink to &quot;デフォルトのトリガーワード&quot;">​</a></h3><ul><li><code>remember</code></li><li><code>save this</code></li><li><code>don&#39;t forget</code></li><li><code>memorize</code></li><li><code>take note</code></li><li>...（詳細はソースコードの設定を参照）</li></ul><h3 id="インタラクションの例" tabindex="-1">インタラクションの例 <a class="header-anchor" href="#インタラクションの例" aria-label="Permalink to &quot;インタラクションの例&quot;">​</a></h3><p><strong>あなたの入力</strong>：</p><blockquote><p>ここでの API レスポンス形式が変わりました。<strong>remember</strong> 今後は <code>data.payload</code> ではなく <code>data.result</code> を使用します。</p></blockquote><p><strong>プラグインが &quot;remember&quot; を検出</strong>：</p><blockquote><p>（バックグラウンドでヒントを注入）：<code>[MEMORY TRIGGER DETECTED] The user wants you to remember something...</code></p></blockquote><p><strong>Agent の反応</strong>：</p><blockquote><p>了解しました。この変更を記憶します。 <em>(バックグラウンドで <code>supermemory.add</code> を呼び出して記憶を保存)</em></p></blockquote><hr><h2 id="詳細設定" tabindex="-1">詳細設定 <a class="header-anchor" href="#詳細設定" aria-label="Permalink to &quot;詳細設定&quot;">​</a></h2><p><code>~/.config/opencode/supermemory.jsonc</code> を変更して、注入動作を調整できます。</p><h3 id="一般的な設定項目" tabindex="-1">一般的な設定項目 <a class="header-anchor" href="#一般的な設定項目" aria-label="Permalink to &quot;一般的な設定項目&quot;">​</a></h3><div class="language-jsonc vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">jsonc</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // ユーザープロファイルを注入するかどうか（デフォルト true）</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;injectProfile&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // 各回に注入するプロジェクト記憶の数（デフォルト 10）</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // 多くすると Agent はプロジェクトをより深く理解できますが、より多くの Token を消費します</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;maxProjectMemories&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">10</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // 各回に注入するユーザープロファイル項目の数（デフォルト 5）</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;maxProfileItems&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">5</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // カスタムトリガーワード（正規表現をサポート）</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;keywordPatterns&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &quot;メモ&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &quot;永続保存&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  ]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">ヒント</p><p>設定を変更した後は、OpenCode を再起動するかプラグインをリロードする必要があります。</p></div><hr><h2 id="よくある質問" tabindex="-1">よくある質問 <a class="header-anchor" href="#よくある質問" aria-label="Permalink to &quot;よくある質問&quot;">​</a></h2><h3 id="q-注入された情報は多くの-token-を消費しますか" tabindex="-1">Q: 注入された情報は多くの Token を消費しますか？ <a class="header-anchor" href="#q-注入された情報は多くの-token-を消費しますか" aria-label="Permalink to &quot;Q: 注入された情報は多くの Token を消費しますか？&quot;">​</a></h3><p><strong>A</strong>: 一部消費しますが、通常は管理可能です。デフォルト設定（10 件のプロジェクト記憶 + 5 件のプロファイル）では、約 500-1000 Token を消費します。現代の大規模言語モデル（Claude 3.5 Sonnet など）の 200k コンテキストに比べれば、これはごくわずかです。</p><h3 id="q-remember-と言っても反応がないのはなぜですか" tabindex="-1">Q: &quot;remember&quot; と言っても反応がないのはなぜですか？ <a class="header-anchor" href="#q-remember-と言っても反応がないのはなぜですか" aria-label="Permalink to &quot;Q: &quot;remember&quot; と言っても反応がないのはなぜですか？&quot;">​</a></h3><p><strong>A</strong>:</p><ol><li>スペルが正しいか確認してください（正規表現マッチをサポート）。</li><li>API Key が正しく設定されているか確認してください（プラグインが初期化されていない場合、トリガーされません）。</li><li>Agent が無視することを決定する可能性があります（プラグインは強制的にヒントを送信しますが、Agent には最終的な決定権があります）。</li></ol><h3 id="q-「関連記憶」はどのように検索されるのですか" tabindex="-1">Q: 「関連記憶」はどのように検索されるのですか？ <a class="header-anchor" href="#q-「関連記憶」はどのように検索されるのですか" aria-label="Permalink to &quot;Q: 「関連記憶」はどのように検索されるのですか？&quot;">​</a></h3><p><strong>A</strong>: これはあなたの <strong>最初のメッセージの内容</strong> に基づいてセマンティック検索されます。最初のメッセージが &quot;Hi&quot; だけの場合、有用な関連記憶は見つからないかもしれませんが、「プロジェクト知識」と「ユーザープロファイル」は依然として注入されます。</p><hr><h2 id="この章のまとめ" tabindex="-1">この章のまとめ <a class="header-anchor" href="#この章のまとめ" aria-label="Permalink to &quot;この章のまとめ&quot;">​</a></h2><ul><li><strong>自動注入</strong> はセッションの最初のメッセージでのみトリガーされます。</li><li><strong>三次元モデル</strong> にはユーザープロファイル、プロジェクト知識、関連記憶が含まれます。</li><li><strong>キーワードトリガー</strong> により、いつでも Agent に記憶を保存するよう命令できます。</li><li><strong>設定ファイル</strong> により、注入される情報量を制御できます。</li></ul><h2 id="次の章の予告" tabindex="-1">次の章の予告 <a class="header-anchor" href="#次の章の予告" aria-label="Permalink to &quot;次の章の予告&quot;">​</a></h2><blockquote><p>次の章では <strong><a href="./../tools/">ツールセット詳解：Agent に記憶を教える</a></strong> を学びます。</p><p>以下のことができるようになります：</p><ul><li><code>add</code>、<code>search</code> などのツールを手動で使用する方法</li><li>間違った記憶を確認・削除する方法</li></ul></blockquote><hr><h2 id="付録-ソースコード参照" tabindex="-1">付録：ソースコード参照 <a class="header-anchor" href="#付録-ソースコード参照" aria-label="Permalink to &quot;付録：ソースコード参照&quot;">​</a></h2><details><summary><strong>クリックしてソースコードの場所を表示</strong></summary><blockquote><p>更新日：2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>機能</th><th>ファイルパス</th><th>行番号</th></tr></thead><tbody><tr><td>注入トリガーロジック</td><td><a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/index.ts#L125-L176" target="_blank" rel="noreferrer"><code>src/index.ts</code></a></td><td>125-176</td></tr><tr><td>キーワード検出</td><td><a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/index.ts#L34-L37" target="_blank" rel="noreferrer"><code>src/index.ts</code></a></td><td>34-37</td></tr><tr><td>プロンプトフォーマット</td><td><a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/services/context.ts#L14-L64" target="_blank" rel="noreferrer"><code>src/services/context.ts</code></a></td><td>14-64</td></tr><tr><td>デフォルト設定</td><td><a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/config.ts#L44-L54" target="_blank" rel="noreferrer"><code>src/config.ts</code></a></td><td>44-54</td></tr></tbody></table><p><strong>重要な関数</strong>：</p><ul><li><code>formatContextForPrompt()</code>: <code>[SUPERMEMORY]</code> テキストブロックを組み立てます。</li><li><code>detectMemoryKeyword()</code>: ユーザーメッセージのトリガーワードを正規表現でマッチングします。</li></ul></details><h2 id="次の章の予告-1" tabindex="-1">次の章の予告 <a class="header-anchor" href="#次の章の予告-1" aria-label="Permalink to &quot;次の章の予告&quot;">​</a></h2><blockquote><p>次の章では <strong><a href="./../tools/">ツールセット詳解：Agent に記憶を教える</a></strong> を学びます。</p><p>以下のことができるようになります：</p><ul><li><code>add</code>、<code>search</code>、<code>profile</code> などの 5 つのコアツールモードを習得</li><li>Agent の記憶を手動で介入・修正する方法</li><li>自然言語を使用して記憶保存をトリガーする</li></ul></blockquote>`,57)])])}const g=a(o,[["render",i]]);export{u as __pageData,g as default};
